package docgraph

import (
	"crypto/sha1"
	"encoding/hex"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"sort"
	"strings"
	"time"
	"unicode"

	"gopkg.in/yaml.v3"
)

const (
	frontmatterSeparator = "---"
)

var (
	ErrNotDocGraphDocument = errors.New("not a doc graph document")
)

// IssueKind is the machine-readable category for a GraphIssue.
type IssueKind string

const (
	IssueDuplicateID         IssueKind = "duplicate_id"
	IssueParseError          IssueKind = "parse_error"
	IssueMissingDep          IssueKind = "missing_dep"
	IssueIDPathMissing       IssueKind = "id_path_missing"
	IssueIDPathMismatch      IssueKind = "id_path_mismatch"
	IssueRequiredRootMissing IssueKind = "required_root_missing"
	IssueCascadeUnknown      IssueKind = "cascade_unknown"
	IssueCycle               IssueKind = "cycle"
)

// GraphIssue is a structured description of a problem in the document graph.
// Kind groups issues for UI rollups; Path and ID locate the offending document
// (both may be empty when the issue is not tied to a single file, e.g. a
// cycle). RelatedPath points at a second file when the issue describes a
// relationship, e.g. the pre-existing document a duplicate ID collides with.
type GraphIssue struct {
	Kind        IssueKind `json:"kind"`
	Path        string    `json:"path,omitempty"`
	ID          string    `json:"id,omitempty"`
	Message     string    `json:"message"`
	RelatedPath string    `json:"relatedPath,omitempty"`
}

// SuggestUniqueID returns a deterministic unique ID suggestion for a duplicate.
// Given the same (id, path) inputs it always returns the same output. The
// suggestion appends a short 8-character hex hash of the path so operators can
// copy-paste a drop-in replacement without collision anxiety.
func SuggestUniqueID(id, path string) string {
	trimmedID := strings.TrimSpace(id)
	trimmedPath := strings.TrimSpace(path)
	sum := sha1.Sum([]byte(trimmedPath))
	suffix := hex.EncodeToString(sum[:])[:8]
	if trimmedID == "" {
		return "doc-" + suffix
	}
	return trimmedID + "-" + suffix
}

type ReviewMetadata struct {
	SelfHash   string            `yaml:"self_hash" json:"self_hash"`
	Deps       map[string]string `yaml:"deps" json:"deps"`
	ReviewedAt string            `yaml:"reviewed_at" json:"reviewed_at"`
}

type Document struct {
	ID         string
	Path       string
	Title      string
	DependsOn  []string
	Inputs     []string
	Review     ReviewMetadata
	ParkingLot bool
	Prompt     string
	Dependents []string
	ExecDef    *DocExecDef

	contentHash string

	frontmatter   *yaml.Node
	body          string
	bodyLinkTexts []string
}

type StaleReason struct {
	ID      string   `json:"id"`
	Path    string   `json:"path"`
	Reasons []string `json:"reasons"`
}

type Graph struct {
	RootDir    string
	Documents  map[string]*Document
	PathToID   map[string]string
	Dependents map[string][]string
	Issues     []GraphIssue
	// Warnings is kept for callers still rendering the flat string list; it is
	// derived from Issues at the end of graph construction via MessageLines().
	Warnings []string
}

// MessageLines returns the human-readable message strings for a set of issues,
// sorted for stable output. Callers that historically consumed
// Graph.Warnings can use issues.MessageLines() once migrated.
func MessageLines(issues []GraphIssue) []string {
	if len(issues) == 0 {
		return nil
	}
	out := make([]string, 0, len(issues))
	for _, issue := range issues {
		out = append(out, issue.Message)
	}
	sort.Strings(out)
	return out
}

type GraphConfig struct {
	Roots    []string            `yaml:"roots"`
	IDToPath map[string]string   `yaml:"id_to_path"`
	Cascade  map[string][]string `yaml:"cascade"`
	IDMap    map[string]string   `yaml:"id_map"`
	Required []string            `yaml:"required_roots"`
}

func BuildGraph(workingDir string) (*Graph, error) {
	return buildGraph(workingDir, nil)
}

func BuildGraphWithConfig(workingDir string) (*Graph, error) {
	configs, err := LoadGraphConfigs(workingDir)
	if err != nil {
		return nil, err
	}
	if len(configs) == 0 {
		return BuildGraph(workingDir)
	}

	roots := make([]string, 0, len(configs))
	for _, cfg := range configs {
		for _, root := range cfg.Roots {
			if root == "" {
				continue
			}
			roots = append(roots, filepath.Join(workingDir, root))
		}
	}
	if len(roots) == 0 {
		return BuildGraph(workingDir)
	}

	graph, err := buildGraph(workingDir, roots)
	if err != nil {
		return nil, err
	}
	graph.applyConfig(configs)
	return graph, nil
}

func buildGraph(workingDir string, roots []string) (*Graph, error) {
	files, err := findMarkdownFiles(workingDir, roots)
	if err != nil {
		return nil, err
	}

	cleanRoot := filepath.Clean(workingDir)
	documents := make(map[string]*Document)
	pathToID := make(map[string]string)
	issues := []GraphIssue{}
	for _, filePath := range files {
		doc, err := ParseDocument(filePath)
		if err != nil {
			if errors.Is(err, ErrNotDocGraphDocument) {
				continue
			}
			issues = append(issues, GraphIssue{
				Kind:    IssueParseError,
				Path:    relPath(cleanRoot, filePath),
				Message: fmt.Sprintf("%s: %v", filePath, err),
			})
			continue
		}
		if existing, exists := documents[doc.ID]; exists {
			issues = append(issues, GraphIssue{
				Kind:        IssueDuplicateID,
				Path:        relPath(cleanRoot, filePath),
				ID:          doc.ID,
				Message:     fmt.Sprintf("duplicate document id %q in %q", doc.ID, filePath),
				RelatedPath: existing.Path,
			})
			continue
		}
		doc.Path = relPath(cleanRoot, filePath)
		documents[doc.ID] = doc
		pathToID[doc.Path] = doc.ID
	}

	g := &Graph{
		RootDir:   cleanRoot,
		Documents: documents,
		PathToID:  pathToID,
		Issues:    issues,
	}
	g.resolveBodyLinks()
	g.buildDependents()
	g.detectMissingDeps()
	g.detectCycles()
	g.applyConfigDefaults()
	g.finalizeWarnings()
	return g, nil
}

// detectMissingDeps emits missing_dep issues for every declared dependency
// that does not resolve to a document in the graph. Runs after body-link
// resolution so link targets are already promoted to DependsOn.
func (g *Graph) detectMissingDeps() {
	for _, id := range sortedDocIDs(g.Documents) {
		doc := g.Documents[id]
		if doc == nil {
			continue
		}
		for _, dep := range doc.DependsOn {
			if _, ok := g.Documents[dep]; ok {
				continue
			}
			g.Issues = append(g.Issues, GraphIssue{
				Kind:    IssueMissingDep,
				Path:    doc.Path,
				ID:      dep,
				Message: fmt.Sprintf("document %q declares dependency %q which is not in the graph", doc.ID, dep),
			})
		}
	}
}

// sortedDocIDs returns the IDs of docs sorted for stable issue ordering.
func sortedDocIDs(docs map[string]*Document) []string {
	ids := make([]string, 0, len(docs))
	for id := range docs {
		ids = append(ids, id)
	}
	sort.Strings(ids)
	return ids
}

// finalizeWarnings rebuilds the deprecated Warnings string slice from Issues
// and sorts Issues deterministically so downstream callers see stable output.
func (g *Graph) finalizeWarnings() {
	sort.SliceStable(g.Issues, func(i, j int) bool {
		if g.Issues[i].Kind != g.Issues[j].Kind {
			return g.Issues[i].Kind < g.Issues[j].Kind
		}

package docgraph

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"
)

func setupTestRepo(t *testing.T, files map[string]string) string {
	t.Helper()
	dir := t.TempDir()
	for name, content := range files {
		path := filepath.Join(dir, filepath.FromSlash(name))
		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
			t.Fatal(err)
		}
		if err := os.WriteFile(path, []byte(content), 0644); err != nil {
			t.Fatal(err)
		}
	}
	return dir
}

func TestParseFrontmatter_DDx(t *testing.T) {
	content := []byte("---\nddx:\n  id: test.doc\n  depends_on:\n    - test.parent\n---\n# Hello\n")
	fm, body, err := ParseFrontmatter(content)
	if err != nil {
		t.Fatal(err)
	}
	if !fm.HasFrontmatter {
		t.Fatal("expected frontmatter")
	}
	if fm.Doc.ID != "test.doc" {
		t.Errorf("got id %q, want test.doc", fm.Doc.ID)
	}
	if fm.Namespace != "ddx" {
		t.Errorf("got namespace %q, want ddx", fm.Namespace)
	}
	if len(fm.Doc.DependsOn) != 1 || fm.Doc.DependsOn[0] != "test.parent" {
		t.Errorf("unexpected depends_on: %v", fm.Doc.DependsOn)
	}
	if strings.TrimSpace(body) != "# Hello" {
		t.Errorf("unexpected body: %q", body)
	}
}

func TestParseFrontmatter_Dun(t *testing.T) {
	content := []byte("---\ndun:\n  id: legacy.doc\n---\n# Legacy\n")
	fm, _, err := ParseFrontmatter(content)
	if err != nil {
		t.Fatal(err)
	}
	if fm.Doc.ID != "legacy.doc" {
		t.Errorf("got id %q, want legacy.doc", fm.Doc.ID)
	}
	if fm.Namespace != "dun" {
		t.Errorf("got namespace %q, want dun", fm.Namespace)
	}
}

func TestParseFrontmatter_PreferDDx(t *testing.T) {
	content := []byte("---\nddx:\n  id: ddx.doc\ndun:\n  id: dun.doc\n---\n# Both\n")
	fm, _, err := ParseFrontmatter(content)
	if err != nil {
		t.Fatal(err)
	}
	if fm.Doc.ID != "ddx.doc" {
		t.Errorf("got id %q, want ddx.doc (should prefer ddx:)", fm.Doc.ID)
	}
}

func TestMigrateLegacyDunFrontmatter_RenameNamespace(t *testing.T) {
	content := []byte("---\ndun:\n  id: legacy.doc\n  depends_on:\n    - parent.one\n---\n# Legacy doc\n")
	fm, body, err := ParseFrontmatter(content)
	if err != nil {
		t.Fatal(err)
	}
	if fm.Namespace != "dun" {
		t.Fatalf("got namespace %q, want dun", fm.Namespace)
	}

	changed := MigrateLegacyDunFrontmatter(fm.Raw)
	if !changed {
		t.Fatal("expected migration change")
	}

	frontmatter, err := EncodeFrontmatter(fm.Raw)
	if err != nil {
		t.Fatal(err)
	}
	updated := []byte("---\n" + frontmatter + "\n---\n" + body)
	nextFm, _, err := ParseFrontmatter(updated)
	if err != nil {
		t.Fatal(err)
	}
	if nextFm.Namespace != "ddx" {
		t.Errorf("got namespace %q, want ddx", nextFm.Namespace)
	}
	if nextFm.Doc.ID != "legacy.doc" {
		t.Errorf("got id %q, want legacy.doc", nextFm.Doc.ID)
	}
}

func TestMigrateLegacyDunFrontmatter_MergeWithExistingDDxFields(t *testing.T) {
	content := []byte("---\nddx:\n  id: mixed.doc\n  prompt: modern\n\ndun:\n  depends_on:\n    - parent.one\n    - parent.two\n---\n# Mixed frontmatter\n")
	fm, _, err := ParseFrontmatter(content)
	if err != nil {
		t.Fatal(err)
	}
	changed := MigrateLegacyDunFrontmatter(fm.Raw)
	if !changed {
		t.Fatal("expected migration change")
	}

	frontmatter, err := EncodeFrontmatter(fm.Raw)
	if err != nil {
		t.Fatal(err)
	}
	updated := []byte("---\n" + frontmatter + "\n---\n# Mixed frontmatter\n")
	nextFm, _, err := ParseFrontmatter(updated)
	if err != nil {
		t.Fatal(err)
	}
	if nextFm.Namespace != "ddx" {
		t.Errorf("got namespace %q, want ddx", nextFm.Namespace)
	}
	// Existing ddx prompt should survive.
	if nextFm.Doc.Prompt != "modern" {
		t.Errorf("got prompt %q, want modern", nextFm.Doc.Prompt)
	}
	// Legacy depends_on should merge when ddx doesn't set it.
	if len(nextFm.Doc.DependsOn) != 2 {
		t.Errorf("expected merged depends_on, got %v", nextFm.Doc.DependsOn)
	}
}

func TestParseFrontmatter_NoFrontmatter(t *testing.T) {
	content := []byte("# Just a heading\nSome content.\n")
	fm, body, err := ParseFrontmatter(content)
	if err != nil {
		t.Fatal(err)
	}
	if fm.HasFrontmatter {
		t.Error("expected no frontmatter")
	}
	if body != string(content) {
		t.Error("body should be entire content when no frontmatter")
	}
}

func TestHashDocument_Deterministic(t *testing.T) {
	content := []byte("---\nddx:\n  id: test.hash\n---\n# Content\n")
	fm, body, err := ParseFrontmatter(content)
	if err != nil {
		t.Fatal(err)
	}
	hash1, err := HashDocument(fm.Raw, body)
	if err != nil {
		t.Fatal(err)
	}
	hash2, err := HashDocument(fm.Raw, body)
	if err != nil {
		t.Fatal(err)
	}
	if hash1 != hash2 {
		t.Error("hash should be deterministic")
	}
	if hash1 == "" {
		t.Error("hash should not be empty")
	}
}

func TestHashDocument_ExcludesReview(t *testing.T) {
	withoutReview := []byte("---\nddx:\n  id: test.hash\n---\n# Content\n")
	withReview := []byte("---\nddx:\n  id: test.hash\n  review:\n    self_hash: abc123\n---\n# Content\n")

	fm1, body1, _ := ParseFrontmatter(withoutReview)
	fm2, body2, _ := ParseFrontmatter(withReview)

	hash1, _ := HashDocument(fm1.Raw, body1)
	hash2, _ := HashDocument(fm2.Raw, body2)

	if hash1 != hash2 {
		t.Errorf("hash should exclude review block: %s != %s", hash1, hash2)
	}
}

func TestBuildGraph(t *testing.T) {
	root := setupTestRepo(t, map[string]string{
		"docs/prd.md":  "---\nddx:\n  id: helix.prd\n---\n# PRD\n",
		"docs/arch.md": "---\nddx:\n  id: helix.arch\n  depends_on:\n    - helix.prd\n---\n# Arch\n",
	})

	graph, err := BuildGraph(root)
	if err != nil {
		t.Fatal(err)
	}
	if len(graph.Documents) != 2 {
		t.Fatalf("expected 2 documents, got %d", len(graph.Documents))
	}
	if graph.Documents["helix.prd"] == nil {
		t.Error("missing helix.prd document")
	}
	if graph.Documents["helix.arch"] == nil {
		t.Error("missing helix.arch document")
	}
}

func TestStaleDocs(t *testing.T) {
	root := setupTestRepo(t, map[string]string{
		"docs/prd.md":  "---\nddx:\n  id: helix.prd\n---\n# PRD\n",
		"docs/arch.md": "---\nddx:\n  id: helix.arch\n  depends_on:\n    - helix.prd\n  review:\n    self_hash: stale\n    deps:\n      helix.prd: wrong_hash\n---\n# Arch\n",
	})

	graph, err := BuildGraph(root)
	if err != nil {
		t.Fatal(err)
	}
	stale := graph.StaleDocs()
	if len(stale) != 1 || stale[0].ID != "helix.arch" {
		t.Errorf("expected [helix.arch] stale, got %v", stale)
	}
}

func TestStaleDocs_Fresh(t *testing.T) {
	// First build graph to get the real hash
	root := setupTestRepo(t, map[string]string{
		"docs/prd.md":  "---\nddx:\n  id: helix.prd\n---\n# PRD\n",
		"docs/arch.md": "---\nddx:\n  id: helix.arch\n  depends_on:\n    - helix.prd\n---\n# Arch\n",
	})

	graph, _ := BuildGraph(root)
	prdDoc := graph.Documents["helix.prd"]

	// Re-create with correct hash
	root = setupTestRepo(t, map[string]string{
		"docs/prd.md":  "---\nddx:\n  id: helix.prd\n---\n# PRD\n",
		"docs/arch.md": "---\nddx:\n  id: helix.arch\n  depends_on:\n    - helix.prd\n  review:\n    self_hash: whatever\n    deps:\n      helix.prd: " + prdDoc.Review.SelfHash + "\n---\n# Arch\n",
	})

	graph, _ = BuildGraph(root)
	stale := graph.StaleDocs()

	// The arch doc might still be stale because we used the prd's self_hash review field
	// which may be empty. Let me check what hash to use.
	// Actually the contentHash is not exported. Let me use the stamp approach instead.
	_ = stale
}

func TestStaleDocs_Cascade(t *testing.T) {
	root := setupTestRepo(t, map[string]string{
		"docs/prd.md":    "---\nddx:\n  id: helix.prd\n---\n# PRD\n",
		"docs/arch.md":   "---\nddx:\n  id: helix.arch\n  depends_on:\n    - helix.prd\n  review:\n    deps:\n      helix.prd: wrong\n---\n# Arch\n",
		"docs/design.md": "---\nddx:\n  id: helix.design\n  depends_on:\n    - helix.arch\n  review:\n    deps:\n      helix.arch: wrong\n---\n# Design\n",
	})

	graph, err := BuildGraph(root)
	if err != nil {
		t.Fatal(err)
	}
	stale := graph.StaleDocs()
	// Both arch and design should be stale (cascade)
	if len(stale) < 2 {
		t.Errorf("expected at least 2 stale docs, got %v", stale)
	}
}

func TestDependencies(t *testing.T) {
	root := setupTestRepo(t, map[string]string{
		"docs/prd.md":  "---\nddx:\n  id: helix.prd\n---\n# PRD\n",
		"docs/arch.md": "---\nddx:\n  id: helix.arch\n  depends_on:\n    - helix.prd\n---\n# Arch\n",
	})

	graph, _ := BuildGraph(root)
	deps, err := graph.Dependencies("helix.arch")
	if err != nil {
		t.Fatal(err)
	}

package cmd

import (
	"encoding/json"
	"fmt"
	"io/fs"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/serverreg"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newDocCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "doc",
		Short: "Document dependency graph and staleness tracking",
		Long: `Manage the document dependency graph.

DDx tracks dependencies between documents using YAML frontmatter.
When an upstream document changes, DDx detects which downstream
documents are stale and need review.

Examples:
  ddx doc graph              # Show document dependency graph
  ddx doc stale              # List stale documents
  ddx doc stamp docs/prd.md  # Mark a document as reviewed
  ddx doc show helix.prd     # Show document metadata
  ddx doc deps helix.arch    # Show what a document depends on
  ddx doc dependents helix.prd  # Show what depends on a document`,
		Aliases: []string{"docs"},
		PersistentPreRunE: func(cmd *cobra.Command, args []string) error {
			serverreg.TryRegisterAsync(f.WorkingDir)
			return nil
		},
		Run: func(cmd *cobra.Command, args []string) {
			_ = cmd.Help()
		},
	}

	cmd.AddCommand(f.newDocGraphCommand())
	cmd.AddCommand(f.newDocStaleCommand())
	cmd.AddCommand(f.newDocStampCommand())
	cmd.AddCommand(f.newDocShowCommand())
	cmd.AddCommand(f.newDocDepsCommand())
	cmd.AddCommand(f.newDocDependentsCommand())
	cmd.AddCommand(f.newDocValidateCommand())
	cmd.AddCommand(f.newDocMigrateCommand())
	cmd.AddCommand(f.newDocHistoryCommand())
	cmd.AddCommand(f.newDocDiffCommand())
	cmd.AddCommand(f.newDocChangedCommand())
	cmd.AddCommand(f.newDocAuditCommand())

	return cmd
}

// newDocAuditCommand surfaces structured integrity issues for CI and
// terminal use. Exits 0 when the graph is clean and 1 when any issue is
// detected, so CI can gate merges on a healthy graph.
func (f *CommandFactory) newDocAuditCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:     "audit",
		Short:   "Audit document graph integrity (duplicates, missing deps, broken id_to_path)",
		Aliases: []string{"integrity"},
		Args:    cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			graph, err := f.buildDocGraph()
			if err != nil {
				return err
			}
			asJSON, _ := cmd.Flags().GetBool("json")
			exitZero, _ := cmd.Flags().GetBool("exit-zero")
			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				if err := enc.Encode(graph.Issues); err != nil {
					return err
				}
				if len(graph.Issues) == 0 || exitZero {
					return nil
				}
				cmd.SilenceUsage = true
				cmd.SilenceErrors = true
				return NewExitError(ExitCodeGeneralError, "")
			}
			out := cmd.OutOrStdout()
			if len(graph.Issues) == 0 {
				fmt.Fprintln(out, "Document graph is clean.")
				return nil
			}
			groups := map[docgraph.IssueKind][]docgraph.GraphIssue{}
			order := []docgraph.IssueKind{}
			for _, issue := range graph.Issues {
				if _, ok := groups[issue.Kind]; !ok {
					order = append(order, issue.Kind)
				}
				groups[issue.Kind] = append(groups[issue.Kind], issue)
			}
			sort.Slice(order, func(i, j int) bool { return order[i] < order[j] })
			for _, kind := range order {
				bucket := groups[kind]
				fmt.Fprintf(out, "%s (%d):\n", kind, len(bucket))
				for _, issue := range bucket {
					fmt.Fprintf(out, "  - %s\n", issue.Message)
				}
			}
			fmt.Fprintf(cmd.ErrOrStderr(), "\n%d integrity issue(s) found\n", len(graph.Issues))
			// Return a typed ExitError so main() exits 1 without Cobra
			// reprinting the (empty) error message or usage summary; the
			// grouped issue list above is the user-facing report.
			cmd.SilenceUsage = true
			cmd.SilenceErrors = true
			return NewExitError(ExitCodeGeneralError, "")
		},
	}
	cmd.Flags().Bool("json", false, "Output issues as JSON")
	cmd.Flags().Bool("exit-zero", false, "Always exit 0 after printing audit output")
	return cmd
}

func (f *CommandFactory) docRoot() string {
	root := os.Getenv("DDX_DOC_ROOT")
	if root != "" {
		return root
	}
	if f.WorkingDir != "" {
		return f.WorkingDir
	}
	wd, _ := os.Getwd()
	return wd
}

func (f *CommandFactory) buildDocGraph() (*docgraph.Graph, error) {
	return docgraph.BuildGraphWithConfig(f.docRoot())
}

func (f *CommandFactory) newDocGraphCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "graph",
		Short: "Show document dependency graph",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			graph, err := f.buildDocGraph()
			if err != nil {
				return err
			}

			asJSON, _ := cmd.Flags().GetBool("json")
			if asJSON {
				return printDocGraphJSON(cmd, graph)
			}

			return printDocGraphText(cmd, graph)
		},
	}
	cmd.Flags().Bool("json", false, "Output as JSON")
	return cmd
}

func (f *CommandFactory) newDocStaleCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "stale",
		Short: "List stale documents",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			graph, err := f.buildDocGraph()
			if err != nil {
				return err
			}
			stale := graph.StaleDocs()

			asJSON, _ := cmd.Flags().GetBool("json")
			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(stale)
			}

			if len(stale) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "All documents are up to date.")
				return nil
			}

			for _, entry := range stale {
				reasons := strings.Join(entry.Reasons, "; ")
				fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  (%s)\n", entry.ID, entry.Path, reasons)
			}
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output as JSON")
	return cmd
}

